    public function getIconPath(string $icon): string
    {
        return static::$iconPaths[$icon] ??
            '<path fill-rule="evenodd" d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zm-8-3a1 1 0 00-.867.5 1 1 0 11-1.731-1A3 3 0 0113 8a3.001 3.001 0 01-2 2.83V11a1 1 0 11-2 0v-1a1 1 0 011-1 1 1 0 100-2zm0 8a1 1 0 100-2 1 1 0 000 2z" clip-rule="evenodd"/>';
    }

    public function renderIconSvg(string $icon, string $size = 'w-4 h-4', string $class = ''): string
    {
        $cacheKey = "{$icon}_{$size}_$class";

        if (! isset(static::$iconCache[$cacheKey])) {
            $path = $this->getIconPath($icon);
            $classes = trim("$size $class");
            static::$iconCache[
                $cacheKey
            ] = "<svg class=\"$classes\" fill=\"currentColor\" viewBox=\"0 0 20 20\">$path</svg>";
        }

        return static::$iconCache[$cacheKey];
    }

    /**
     * @param  array<string, string>  $icons
     */
    public static function registerIcons(array $icons): void
    {
        static::$iconPaths = array_merge(static::$iconPaths, $icons);
        static::$iconCache = [];
    }
}
